//go:build vectors

package main

import (
	"context"
	"flag"
	"log/slog"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
	"github.com/a<HOME>/agentic-rag-mcp/internal/ingest"
	"github.com/a<HOME>/agentic-rag-mcp/internal/search"
	"github.com/a<HOME>/agentic-rag-mcp/internal/server"
)

func main() {
	configPath := flag.String("config", "", "Path to config JSON file (optional)")
	flag.Parse()

	// Load configuration
	cfg, err := config.Load(*configPath)
	if err != nil {
		slog.Error("loading config", "error", err)
		os.Exit(1)
	}

	// Configure logging
	var logLevel slog.Level
	switch cfg.Log.Level {
	case "debug":
		logLevel = slog.LevelDebug
	case "warn":
		logLevel = slog.LevelWarn
	case "error":
		logLevel = slog.LevelError
	default:
		logLevel = slog.LevelInfo
	}
	handler := slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{Level: logLevel})
	slog.SetDefault(slog.New(handler))

	slog.Info("starting knowledge-mcp",
		"backend", cfg.Embedder.Backend,
		"model", cfg.Embedder.Model,
		"dimensions", cfg.Embedder.Dimensions,
		"indexPath", cfg.IndexPath,
	)

	// Construct embedder
	emb, err := embedder.NewEmbedder(cfg.Embedder)
	if err != nil {
		slog.Error("constructing embedder", "error", err)
		os.Exit(1)
	}
	defer emb.Close()

	// Open or create bleve index
	ix, err := ingest.NewIndexer(cfg.IndexPath, cfg.Embedder.Dimensions)
	if err != nil {
		slog.Error("opening index", "error", err)
		os.Exit(1)
	}
	defer ix.Close()

	// Create pipeline
	pipeline := ingest.NewPipeline(ix, emb, cfg.Security, cfg.Knowledge.MaxChunkSize)

	// Index global sources if configured
	if len(cfg.Knowledge.GlobalSources) > 0 {
		slog.Info("indexing global sources", "count", len(cfg.Knowledge.GlobalSources))
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
		result, err := pipeline.IndexGlobalSources(ctx, cfg.Knowledge.GlobalSources)
		cancel()
		if err != nil {
			slog.Error("indexing global sources", "error", err)
		} else {
			slog.Info("global sources indexed",
				"indexed", result.Indexed,
				"unchanged", result.Unchanged,
				"chunks", result.Chunks,
				"duration", result.Duration,
			)
		}
	}

	// Create searcher
	searcher := search.NewSearcher(ix.BleveIndex(), emb, cfg.Search)

	// Create and run MCP server
	srv := server.New(pipeline, searcher, emb, cfg)

	// Setup graceful shutdown
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGTERM, syscall.SIGINT)

	go func() {
		sig := <-sigChan
		slog.Info("received signal, shutting down", "signal", sig)
		cancel()
	}()

	slog.Info("knowledge-mcp server ready")
	if err := srv.Run(ctx); err != nil {
		slog.Error("server error", "error", err)
		os.Exit(1)
	}

	slog.Info("knowledge-mcp server stopped")
}
